import React, { useState } from 'react';
import { Alert, Typography, IconButton, Dialog, DialogTitle, DialogContent, DialogActions, Button, Select, MenuItem, FormControl, CircularProgress, Box } from '@mui/material';
import { Settings as SettingsIcon } from '@mui/icons-material';
import { useSelectedEventContext } from '@/hooks/useSelectedEventContext';
import { EventServices } from '@/api';
import { EventResult } from '@/types/event.types';
import { saveSelectedEventContext } from '@/utils/eventContext';
import { UnixDateTimeToReadable } from '@/utils/common';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';
import { logger } from '@/utils/logger';

export const EventAlert: React.FC = () => {
    const { selectedEvent } = useSelectedEventContext();
    const [openDialog, setOpenDialog] = useState(false);
    const [events, setEvents] = useState<EventResult[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedEventId, setSelectedEventId] = useState<string>('');

    useBodyScrollLock(openDialog);

    const handleSettingsClick = () => {
        setOpenDialog(true);
        setSelectedEventId(selectedEvent?.id || '');
        fetchEvents();
    };

    const fetchEvents = async () => {
        setIsLoading(true);
        try {
            const response = await EventServices.GetEvents({ pageNumber: 1, pageSize: 100 });
            if (response.data.status === 200 && response.data.result?.items) {
                setEvents(response.data.result.items);
            }
        } catch (error) {
            logger.error('EventAlert', 'Error fetching events', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleConfirmSelection = () => {
        const selected = events.find(e => e.id === selectedEventId);
        if (selected) {
            saveSelectedEventContext(selected);
            setOpenDialog(false);
            // Reload the page to reflect the new event selection
            window.location.reload();
        }
    };

    const handleCloseDialog = () => {
        setOpenDialog(false);
    };

    return (
        <>
            <Alert
                severity="warning"
                sx={{
                    mb: 1,
                    py: 0.5,
                    px: 1.5,
                    display: 'flex',
                    alignItems: 'center',
                    border: 1,
                    borderColor: 'error.main'
                }}
                action={
                    <IconButton
                        color="inherit"
                        size="small"
                        aria-label="Change selected event"
                        onClick={handleSettingsClick}
                    >
                        <SettingsIcon fontSize="small" />
                    </IconButton>
                }
            >
                <Typography variant="body2" sx={{ fontSize: '0.875rem', fontWeight: 500 }}>
                    {selectedEvent
                        ? `Selected Event: ${selectedEvent.id}`
                        : 'No event selected. Please select an event to enable features.'}
                </Typography>
            </Alert>

            {/* Event Selection Dialog */}
            <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
                <DialogTitle>Select Event</DialogTitle>
                <DialogContent sx={{ pt: 2, minHeight: '120px' }}>
                    {isLoading ? (
                        <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
                            <CircularProgress />
                        </Box>
                    ) : events.length > 0 ? (
                        <FormControl fullWidth>
                            <Select
                                value={selectedEventId}
                                onChange={(e) => setSelectedEventId(e.target.value)}
                                displayEmpty
                            >
                                <MenuItem value="">
                                    <Typography variant="body2" color="text.secondary">--Select--</Typography>
                                </MenuItem>
                                {events.map((event) => (
                                    <MenuItem key={event.id} value={event.id}>
                                        <Box sx={{ display: 'flex', flexDirection: 'column', width: '100%' }}>
                                            <Typography variant="body2" sx={{ fontWeight: 500 }}>
                                                {event.id}
                                            </Typography>
                                            <Typography variant="caption" color="text.secondary">
                                                {UnixDateTimeToReadable(event.startDateTime)}
                                            </Typography>
                                        </Box>
                                    </MenuItem>
                                ))}
                            </Select>
                        </FormControl>
                    ) : (
                        <Typography sx={{ py: 2, textAlign: 'center', color: 'text.secondary' }}>
                            No events available
                        </Typography>
                    )}
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleCloseDialog} color="inherit">Cancel</Button>
                    <Button 
                        onClick={handleConfirmSelection} 
                        variant="contained"
                        disabled={!selectedEventId || isLoading}
                    >
                        Select
                    </Button>
                </DialogActions>
            </Dialog>
        </>
    );
};