import * as React from 'react';
import Box from '@mui/material/Box';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import { Alert, Typography } from '@mui/material';
import { useNavigate, useLocation } from '@tanstack/react-router';
import { GetUserRoles } from '@/utils/token';
import { Roles } from '@/types/api.types';
import { hasRequiredRole } from '@/utils/roles';
import { NotFound } from '@/pages/special/NotFound';
import { EventAlert } from './EventAlert';
import { AttendeeTabs } from '@/constants/Routes';
import { useSelectedEventContext } from '@/hooks/useSelectedEventContext';
import { PageCard } from './PageCard';
import PersonAddIcon from '@mui/icons-material/PersonAdd';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PeopleIcon from '@mui/icons-material/People';
import BarChartIcon from '@mui/icons-material/BarChart';

interface TabConfig {
    label: string;
    path: string;
    role?: Roles | Roles[];  // Support single role or array of roles
    icon?: string;  // Icon identifier
}

// Helper function to get icon component
const getIconComponent = (iconName?: string) => {
    if (!iconName) return undefined;
    
    switch (iconName) {
        case 'register':
            return <PersonAddIcon />;
        case 'checkin':
            return <CheckCircleIcon />;
        case 'attendee':
            return <PeopleIcon />;
        case 'stats':
            return <BarChartIcon />;
        default:
            return undefined;
    }
};

interface PageTabsProps {
    tabs: TabConfig[];
    children?: React.ReactNode;
}

export const PageTabs: React.FC<PageTabsProps> = ({ tabs, children }) => {
    const [value, setValue] = React.useState<number | false>(0);
    const navigate = useNavigate();
    const { pathname } = useLocation();
    const userRoles = GetUserRoles();
    const { selectedEvent } = useSelectedEventContext();
    
    // Check if current tabs are attendee tabs or adhoc tabs
    const isAttendeeTabs = React.useMemo(() => {
        return tabs === AttendeeTabs;
    }, [tabs]);
        
    const requiresEventSelection = React.useMemo(() => {
        return isAttendeeTabs;
    }, [isAttendeeTabs]);

    // Check if current page requires specific roles
    const currentTab = React.useMemo(() => {
        return tabs.find(tab => tab.path === pathname);
    }, [tabs, pathname]);
    
    // Check if user has access to current page
    const hasCurrentPageAccess = React.useMemo(() => {
        return hasRequiredRole(currentTab?.role, userRoles);
    }, [currentTab, userRoles]);
    
    // Filter tabs based on user roles
    const filteredTabs = React.useMemo(() => {
        return tabs.filter(tab => hasRequiredRole(tab.role, userRoles));
    }, [tabs, userRoles]);

    React.useEffect(() => {
        const tabIndex = filteredTabs.findIndex(tab => tab.path === pathname);
        setValue(tabIndex >= 0 ? tabIndex : false);
    }, [pathname, filteredTabs]);

    const handleChange = React.useCallback((_event: React.SyntheticEvent, newValue: number) => {
        setValue(newValue);
        const targetPath = filteredTabs[newValue].path.split('?')[0];
        navigate({ to: targetPath });
    }, [navigate, filteredTabs]);

    const renderedTabs = React.useMemo(() => (
        filteredTabs.map((tab, index) => {
            const icon = getIconComponent(tab.icon);
            return (
                <Tab 
                    key={index} 
                    icon={icon}
                    label={!icon ? tab.label : undefined}
                    iconPosition="top"
                    sx={{ 
                        minHeight: { xs: 48, sm: 64 },
                        padding: { xs: '8px 4px', sm: '12px 8px' },
                        textTransform: 'none'
                    }}
                />
            );
        })
    ), [filteredTabs]);
    
    // If user doesn't have access to current page, show NotFound
    if (!hasCurrentPageAccess) {
        return <NotFound />;
    }
    
    // If no tabs are accessible after role filtering, show NotFound
    if (filteredTabs.length === 0) {
        return <NotFound />;
    }

    return (
        <Box sx={{ maxWidth: 720, mx: 'auto', px: { xs: 1, sm: 2 } }}>
            <Box
                sx={{
                    width: '100%',
                    borderBottom: 1,
                    borderColor: 'divider',
                    marginBottom: 1,
                    // Improve touch responsiveness
                    touchAction: 'pan-y', // Allow vertical scrolling but handle horizontal touches
                    userSelect: 'none', // Prevent text selection during swipes
                    WebkitUserSelect: 'none',
                    WebkitTouchCallout: 'none'
                }}
            >
                <Tabs value={value} onChange={handleChange} centered>
                    {renderedTabs}
                </Tabs>
            </Box>

            {/* Event Alert for Attendee and Adhoc Tabs - just above the content/cards */}
            {requiresEventSelection && <EventAlert />}

            {/* Show content or empty state message */}
            {!requiresEventSelection ? (
                children
            ) : selectedEvent ? (
                children
            ) : (
                <PageCard>
                    <Alert severity="info">
                        <Typography variant="h6" gutterBottom>
                            No Event Selected
                        </Typography>
                        <Typography>
                            Please select an event from the settings above to access {isAttendeeTabs ? 'attendee' : 'adhoc'} features.
                        </Typography>
                    </Alert>
                </PageCard>
            )}
        </Box>
    );
};

